<template><div class="page-container enterprise-list-page"><div class="page-card page-flex-card compact-list-card enterprise-list-card"><div class="header"><h2>面试管理</h2><p>跟踪面试邀请确认状态，录入面试评价。</p></div><el-divider/><el-table :data="list" stripe v-loading="loading"><el-table-column prop="interviewTime" label="面试时间" width="180"/><el-table-column label="方式" width="90"><template #default="{row}"><el-tag>{{row.interviewType===2?'线上':'现场'}}</el-tag></template></el-table-column><el-table-column prop="location" label="地点/链接" min-width="180" show-overflow-tooltip/><el-table-column label="学生确认" width="110"><template #default="{row}"><el-tag :type="row.studentStatus===1?'success':row.studentStatus===2?'danger':'warning'">{{['待确认','已确认','已拒绝'][row.studentStatus]}}</el-tag></template></el-table-column><el-table-column prop="remark" label="备注" min-width="160" show-overflow-tooltip/><el-table-column label="操作" width="220"><template #default="{row}"><el-button text type="primary" @click="edit(row)">修改</el-button><el-button text type="success" @click="openFeedback(row)">评价</el-button></template></el-table-column></el-table><div class="pagination-wrap"><el-pagination v-model:current-page="query.pageNum" :total="total" background layout="total,prev,pager,next" @current-change="load"/></div></div><el-dialog v-model="dialog" :title="mode==='edit'?'修改面试':'录入面试评价'" width="620px"><el-form :model="form" label-width="100px"><template v-if="mode==='edit'"><el-form-item label="面试时间"><el-date-picker v-model="form.interviewTime" type="datetime" value-format="YYYY-MM-DD HH:mm:ss" style="width:100%"/></el-form-item><el-form-item label="地点/链接"><el-input v-model="form.location"/></el-form-item><el-form-item label="联系人"><el-input v-model="form.contact"/></el-form-item><el-form-item label="备注"><el-input v-model="form.remark" type="textarea" :rows="3"/></el-form-item></template><template v-else><el-form-item label="面试官"><el-input v-model="form.interviewer"/></el-form-item><el-form-item label="评分"><el-slider v-model="form.score" :max="100" show-input/></el-form-item><el-form-item label="是否通过"><el-radio-group v-model="form.isPass"><el-radio :value="1">通过</el-radio><el-radio :value="0">不通过</el-radio></el-radio-group></el-form-item><el-form-item label="评价"><el-input v-model="form.content" type="textarea" :rows="4"/></el-form-item></template></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{reactive,ref,onMounted}from'vue';import{ElMessage}from'element-plus';import{enterpriseApi}from'@/api';const query=reactive({pageNum:1,pageSize:10});const list=ref([]),total=ref(0),loading=ref(false),dialog=ref(false),mode=ref('edit');const form=reactive({});const load=async()=>{loading.value=true;try{const r=await enterpriseApi.interviewList(query);list.value=r.data.records;total.value=Number(r.data.total)}finally{loading.value=false}};const edit=row=>{mode.value='edit';Object.keys(form).forEach(k=>delete form[k]);Object.assign(form,row);dialog.value=true};const openFeedback=row=>{mode.value='feedback';Object.keys(form).forEach(k=>delete form[k]);Object.assign(form,{noticeId:row.id,score:80,isPass:1});dialog.value=true};const save=async()=>{mode.value==='edit'?await enterpriseApi.updateInterview(form):await enterpriseApi.feedback(form);ElMessage.success('保存成功');dialog.value=false;load()};onMounted(load)</script>
<style scoped>.header h2{margin-bottom:6px}.header p{color:#909399}</style>
